1	const toKey = (x: number, y: number): string => `${x},${y}`;
2	const fromKey = (key: string): [number, number] => {
3	  const [x, y] = key.split(",").map(Number);
4	  return [x, y];
5	};
6	
7	export function nextGeneration(
8	  livingCells: [number, number][]
9	): [number, number][] {
10	  const alive = new Set(livingCells.map(([x, y]) => toKey(x, y)));
11	  const neighborCounts = new Map<string, number>();
12	
13	  for (const [x, y] of livingCells) {
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const key = toKey(x + dx, y + dy);
18	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const nextLivingCells: [number, number][] = [];
24	  for (const [key, count] of neighborCounts) {
25	    if (count === 3 || (count === 2 && alive.has(key))) {
26	      nextLivingCells.push(fromKey(key));
27	    }
28	  }
29	
30	  return nextLivingCells;
31	}

